import chromadb

client = chromadb.Client()
collection = client.create_collection(name="my_collection")

def add_doc(doc_id, content, metadata):
    collection.add(
        documents=[content],
        metadatas=[metadata],
        ids=[doc_id]
    )

def search(query_text):
    return collection.query(
        query_texts=[query_text],
        n_results=2
    )

